<?php
namespace Yellowstep\ElementorEditor\Safety;
use WP_Error; use Yellowstep\ElementorEditor\Elementor\DataStore;
if (!defined('ABSPATH')) { exit; }
final class Snapshots { public const META_KEY='_yellowstep_editor_snapshot'; public static function create(int $postId,string $note=''): void { $raw=get_post_meta($postId,'_elementor_data',true); add_post_meta($postId,self::META_KEY,['time'=>current_time('mysql'),'user_id'=>get_current_user_id(),'note'=>sanitize_text_field($note),'data'=>$raw]); } public static function all(int $postId): array { $snaps=get_post_meta($postId,self::META_KEY); $items=[]; foreach($snaps as $i=>$s){$items[]=['index'=>$i,'time'=>$s['time']??'','note'=>$s['note']??'','user_id'=>$s['user_id']??''];} return $items; } public static function rollback(int $postId,?int $index=null){ $snaps=get_post_meta($postId,self::META_KEY); if(empty($snaps)){return new WP_Error('not_found','No snapshots found.',['status'=>404]);} $snap=($index===null)?end($snaps):($snaps[$index]??null); if(!$snap||!isset($snap['data'])){return new WP_Error('not_found','Snapshot not found.',['status'=>404]);} update_post_meta($postId,'_elementor_data',wp_slash($snap['data'])); DataStore::clearCache($postId); return ['rolled_back'=>true,'post_id'=>$postId]; } }
